const body = $json.body || {};
let userText = '';

try {
  // 1. 获取飞书传来的原始 content 字符串并解析为 JSON 对象
  const rawContent = body?.event?.message?.content || '{}';
  const parsedContent = JSON.parse(rawContent);

  // 2. 智能判断消息类型并提取文本
  if (parsedContent.text) {
    // 形态 A：普通纯文本消息
    userText = parsedContent.text;
  } else if (parsedContent.content && Array.isArray(parsedContent.content)) {
    // 形态 B：富文本/带换行的消息 (Post 类型)
    let extractedTexts = [];

    // 遍历飞书的富文本嵌套数组，把所有 tag 为 text 的内容抠出来
    parsedContent.content.forEach(paragraph => {
      if (Array.isArray(paragraph)) {
        paragraph.forEach(element => {
          // 剔除掉 @机器人的文本，只保留实际文字
          if (element.tag === 'text' && element.text) {
            extractedTexts.push(element.text);
          }
        });
      }
    });
    // 把所有文字片段拼装回一段完整的长文本
    userText = extractedTexts.join('');
  }
} catch (e) {
  // 兜底方案：如果解析彻底失败，直接强行塞入原始字符
  userText = body?.event?.message?.content || '';
}

// 去除首尾多余空格
userText = userText.trim();

// 3. 提取其他必要参数 (群ID和追踪ID)
// 这里的默认群ID作为本地测试的兜底保障
const chatId = body?.event?.message?.chat_id || 'YOUR_CHAT_ID';
const traceId = `${Date.now()}-${Math.random().toString(16).slice(2, 8)}`;

// 4. 将处理好的数据打包传给下一个节点
return {
  json: {
    ...$json,
    userText: userText,
    chatId: chatId,
    traceId: traceId
  }
};

const raw = $input.first().json.output || '';

const defaultPlan = {
  route: 'sql_analysis',
  reason: '默认进入数据分析路径',
  needChart: true,
  needExcel: false,
  sqlFocus: ''
};

let parsed = null;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = defaultPlan;
}

const route = parsed.route === 'direct_reply' ? 'direct_reply' : 'sql_analysis';

return {
  json: {
    ...$input.first().json,
    routePlan: {
      ...defaultPlan,
      ...parsed,
      route
    }
  }
};

