const rawText = $input.first().json.output || '';
let cleanText = rawText;

let chartJson = null;
let hasChart = false;
let excelData = [];
let hasExcel = false;

const excelRegex = /```(?:excel_data)\s*([\s\S]*?)(?:```|$)/i;
const excelMatch = cleanText.match(excelRegex);
if (excelMatch && excelMatch[1]) {
  cleanText = cleanText.replace(excelMatch[0], '').trim();
  try {
    const parsedExcel = JSON.parse(excelMatch[1].trim());
    if (Array.isArray(parsedExcel)) {
      excelData = parsedExcel;
      hasExcel = parsedExcel.length > 0;
    }
  } catch (e) {
    console.log('Excel 数据格式错误，解析失败:', e.message);
  }
}

const chartRegex = /```(?:json|JSON)\s*([\s\S]*?)(?:```|$)/;
const chartMatch = cleanText.match(chartRegex);
if (chartMatch && chartMatch[1]) {
  cleanText = cleanText.replace(chartMatch[0], '').trim();
  try {
    const parsedChart = JSON.parse(chartMatch[1].trim());
    if (parsedChart && typeof parsedChart === 'object' && !Array.isArray(parsedChart)) {
      chartJson = parsedChart;
      hasChart = true;
    }
  } catch (e) {
    console.log('图表 JSON 格式错误，解析失败:', e.message);
  }
}

cleanText = cleanText.replace(/###?\s*[四五六七八九]?[、\.]?(可视化分析|图表展示|数据明细).*$/gm, '').trim();

return {
  json: {
    cleanText,
    chartJson,
    hasChart,
    excelData,
    hasExcel
  }
};

