  (function() {
    // 1. 【防空处理】获取核心数据，如果为空则赋予默认值
    const textData = $node["分离文本和图表1"].json["cleanText"] || "数据处理中，未返回分析文本。";
    const excelData = $node["分离文本和图表1"].json["excelData"] || [];

    // 【防空处理】获取图片 Key。因为有可能没画图，如果节点不存在或没执行，用 try-catch 防止整个表达式崩溃
    let imageKey = null;
    try {
        // 注意：这里的 '上传图片' 请替换为你实际将图表传给飞书并获取 image_key 的那个节点名称
        imageKey = $node["上传图片1"].json["data"]["image_key"];
    } catch(e) {
        imageKey = null; 
    }

    // 2. 基础组件：先放入“文字分析”
    let elements = [
      {
        "tag": "div",
        "text": { "tag": "lark_md", "content": textData }
      }
    ];

    // 3. 智能注入：如果有图表（image_key），就在文字下面追加“图片组件”
    if (imageKey) {
        elements.push({
            "tag": "img",
            "img_key": imageKey,
            "alt": { "tag": "plain_text", "content": "数据可视化图表" },
            "mode": "fit_horizontal",
            "preview": true
        });
    }

    // 4. 智能注入：如果有明细数据（excelData），就在最下方追加“原生表格组件”
    if (Array.isArray(excelData) && excelData.length > 0) {
       // 提取表头
       const keys = Object.keys(excelData[0]);
       const columns = keys.map(key => ({
           "name": key,
           "display_name": key,
           "data_type": "text" // 统一转为 text，防止飞书解析格式报错
       }));

       // 【防空处理】遍历数据行，把所有 null 或数字强转为字符串，防止飞书渲染崩溃
       const rows = excelData.map(row => {
           let safeRow = {};
           for(let k in row) safeRow[k] = String(row[k] || "");
           return safeRow;
       });

       // 增加一条优雅的华丽分割线
       elements.push({ "tag": "hr" });

       // 放入自带翻页功能的表格
       elements.push({
           "tag": "table",
           "page_size": 10, // 每页 5 行，自带翻页按钮
           "row_height": "low",
           "header_style": {
               "bold": true,
               "lines": 1
           },
           "columns": columns,
           "rows": rows
       });
    }

    // 5. 组装终极飞书 V2 卡片
    return JSON.stringify({
      "schema": "2.0",
      "config": { "update_multi": true, "wide_screen_mode": true },
      "header": {
        "title": { "tag": "plain_text", "content": "📊 智能数据中台洞察" },
        "template": "blue"
      },
      "body": {
         "direction": "vertical",
         "elements": elements
      }
    });
  })()
}}

