  (function() {
    try {
      let userText = "";

      // 1. 安全获取【任务预处理】的内容 (注意必须加 .first())
      const preProcessNode = $('任务预处理').first();
      if (preProcessNode && preProcessNode.json.userText) {
         userText = preProcessNode.json.userText;
      } 
      // 2. 如果没获取到，回退找原始 Webhook 的消息 
      // ⚠️ 注意：请确保你画布最开头的触发节点真的叫 Webhook1，如果不是请改名
      else {
         const rawContent = $('Webhook1').first().json.body.event.message.content;
         userText = JSON.parse(rawContent).text;
      }

      // 3. 安全获取当前节点的 routePlan
      // 用 JSON.stringify(..., null, 2) 还能让输出带缩进，好看一万倍
      const routePlan = $json.routePlan ? JSON.stringify($json.routePlan, null, 2) : '{}';

      // 4. 返回拼接结果
      return `用户问题: ${userText}\n调度计划: ${routePlan}`;

    } catch (error) {
      // 终极防崩溃：如果上面任何一步写错了，直接把错误原因打印出来！
      return `⚠️ 解析过程发生错误: ${error.message}`;
    }
  })()
}}
